const item = $input.item.json;

// Simulated classification (in production, this would call Anthropic API)
// For now, use heuristic classification based on source platform and content
const sourceUrl = item.source_url || '';
const snippet = item.raw_snippet || '';

// Default classification
let indicatorType = 'loss';
let reason = 'Public review or discussion detected';
let sentimentScore = -0.3;

// Simple heuristics for classification
const lowerSnippet = snippet.toLowerCase();
const lowerUrl = sourceUrl.toLowerCase();

if (lowerSnippet.includes('love') || lowerSnippet.includes('great') || lowerSnippet.includes('recommend') || lowerSnippet.includes('best')) {
  indicatorType = 'win';
  reason = 'Positive buyer sentiment detected';
  sentimentScore = 0.6;
} else if (lowerSnippet.includes('switch') || lowerSnippet.includes('migrat') || lowerSnippet.includes('moved to') || lowerSnippet.includes('replaced')) {
  indicatorType = 'switch';
  reason = 'Product switching signal detected';
  sentimentScore = -0.1;
} else if (lowerSnippet.includes('terrible') || lowerSnippet.includes('worst') || lowerSnippet.includes('hate') || lowerSnippet.includes('avoid')) {
  indicatorType = 'loss';
  reason = 'Strong negative buyer sentiment detected';
  sentimentScore = -0.7;
}

return [{
  json: {
    id: item.id,
    user_id: item.user_id,
    company_name: item.company_name,
    company_id: item.company_id,
    indicator_type: indicatorType,
    reason: reason,
    sentiment_score: sentimentScore,
    source_url: item.source_url,
    source_platform: item.source_platform
  }
}];
